var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"라미아라는 여자가 있습니다.","JPN":"ラミアという女がいました。","ENG":"There is a woman named Lamia.","TWN":"有個叫拉米亞的女人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"사람 운명을 바꿔준다는 언더그라운드의 유명한 점쟁이.","JPN":"人の運命を変えてくれるという、アンダーグラウンドで有名な占い師。","ENG":"She is a famous fortune-teller in the Underground, known for altering people's fates.","TWN":"她是G1出了名的占卜師，能改變一個人的命運。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그 유명세와 달리, 어디에서 지내는지 어디로 가야 만날 수 있는지는 아무도 모릅니다.","JPN":"でも、あれほど有名なのにどこに暮らしているのか、どこで会えるのかは誰も知りません。","ENG":"But despite her popularity, no one knows where she lives or where to meet her.","TWN":"但不同於她的名氣，沒人知道她住在哪裡，也不知道該去哪裡找她。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"항간에선 그녀가 좋은 술이 있는 술집에 자주 들른다고 하더군요.","JPN":"巷では彼女がいいお酒のあるバーによく出入りしていると言われています。","ENG":"There's a rumor that she often visits bars serving high-quality alcohol.","TWN":"聽說她常在有好酒的酒吧出沒。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 가게들도 저마다 들이는 술의 품질을 올리기 위해 노력한답니다.","JPN":"それでお店もお酒の品質を上げるために頑張っています。","ENG":"And that's why all the bars are doing their best to improve the quality of their drinks.","TWN":"所以各家店都在努力提升酒的品質。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자가 나타났다는 얘기만으로도 가게에 찾아오는 손님이 몰려서 경쟁력이 생길 정도니까요.","JPN":"あの女が現われたという話だけでも、店を訪ねるお客が多すぎて競争力を得るくらいですから。","ENG":"Just hearing that she had appeared in some bar is enough to attract customers.","TWN":"光是聽說她曾光顧，客人就會蜂擁而至，讓那間店生意興隆。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"저 사람. 신고라도 해야 하는 거 아냐?","JPN":"あの人、通報でもした方がいいんじゃないか？","ENG":"Don't you think we should report him to the police?","TWN":"那個人……是不是該報警啊？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"피를 엄청 흘리고 있는데… 괜찮은 건가?","JPN":"めちゃくちゃ血が流れてるんだけど……大丈夫なのかな？","ENG":"He's bleeding a lot... Do you think he's okay?","TWN":"他流了好多血……真的沒事嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어머, 피범벅이 돼서 혼자 술을 마시는 남자라니. 너무 낭만적이잖아?","JPN":"あら、血まみれで1人でお酒を飲む男だなんて。とてもロマンチックね。","ENG":"Oh, dear. A bloodied man drinking all by himself? How romantic it is.","TWN":"哎呀，全身是血卻一個人喝酒的男人，太浪漫了吧？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"일 없으니 꺼져.","JPN":"用はない、失せろ。","ENG":"It's none of your business, so piss off.","TWN":"沒事就滾。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"아하하, 귀엽네. 다친 새끼늑대가 으르렁대는 것 같아.","JPN":"あはは、可愛いわ。怪我したオオカミの子どもが唸ってるみたい。","ENG":"Ah hah hah, how cute. You're like a wounded wolf cub, growling at others.","TWN":"哈哈，好可愛，像受傷的小狼在低吼呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"누구 말상대나 하러 온 거 아니니 좋게 말로 할 때 꺼지라고.","JPN":"誰かと話すために来ているわけでない。手を出す前に失せろって言っているんだ。","ENG":"I'm not here to chit chat, so leave me alone when I ask nicely.","TWN":"我不是來找人聊天的，趁我好好說話時快滾。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"알았어. 얌전히 옆자리에서 술만 마실 테니까.","JPN":"わかったわ。大人しく隣でお酒だけ飲むから。","ENG":"All right. Then I'll just silently drink beside you.","TWN":"好好好，我就安靜坐在旁邊喝酒。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"에잇.","JPN":"えいっ。","ENG":"Hmp!","TWN":"喂。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"큭…?! 뭐하는 짓이야!","JPN":"くっ……！？　何をしやがる！","ENG":"Kgh...?! What the hell was that for?!","TWN":"嗚……？！你在幹什麼！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"상처 좀 소독했어. 이대로는 술이 아니라 피비린내에 취해버릴 테니까.","JPN":"ちょっと傷の消毒ね。このままだとお酒じゃなくて血の匂いで酔いそうだったから。","ENG":"I disinfected your wound. Because I feel like I'll get drunk off the stench of blood rather than booze at this rate.","TWN":"幫你消毒傷口而已。再這樣下去，你就不是醉酒，而是醉在血腥味了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어때? 술로 아픔을 잊는 것보다 훨씬 효율적이지?","JPN":"どう？　お酒で苦痛を忘れるよりはずっと効率的でしょう？","ENG":"How is it? It's way more effective than drinking your pain away, isn't it?","TWN":"怎樣？比起用酒忘記痛苦更有效率吧？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"……치유능력인가? 그런 류의 카운터는 드물다고 들었는데.","JPN":"……治癒能力か？　そんな類のカウンターは少ないと聞いたんだが。","ENG":"...A healing ability? I heard Counters with those kinds of abilities are hard to find.","TWN":"……這是治癒能力嗎？這類的處置方式很少見。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"마음에 들어? 치유만 할 수 있는 건 아니지만 말이야.","JPN":"気に入った？　他にもできることは色々あるけどね。","ENG":"Do you like it? And it's not just healing that I can do, you know.","TWN":"你喜歡嗎？我可不只會治療喔。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"괜한 오지랖이군. 자원봉사라도 다니나?","JPN":"余計なお世話だ。ボランティアでもしてるのか？","ENG":"Aren't you nosy? Are you a volunteer for something or what?","TWN":"少管閒事。你是做義工的嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"딱히 공짜로 해준다곤 안 했어.","JPN":"別にただでやってあげるとか言ってないわよ？","ENG":"I didn't say it was for free.","TWN":"我可沒說免費哦。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"돈 없다. 뜯어낼 목적이라면 상대 잘못 골랐어.","JPN":"お金はない。巻き上げるつもりなら相手が悪かったな。","ENG":"I got no money. If you're trying to rip someone off, you chose the wrong guy.","TWN":"我沒錢。要敲詐的話，你找錯人了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그래? 손에 피 묻히고 술 마시러 다니는 사람은 보통 돈이 많던데.","JPN":"そう？　血まみれの手で飲みに来る人は普通、お金をたくさん持ってたわよ。","ENG":"Oh, really? I thought people who drink with blood on their hands are usually loaded.","TWN":"是嗎？手上沾滿血還來喝酒的人，通常都很有錢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"영화를 너무 많이 봤군.","JPN":"映画の見すぎだ。","ENG":"Guess you've been watching too many movies.","TWN":"你電影看太多了。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"좋아. 돈은 안 받을게. 대신 얘기나 좀 해줘.","JPN":"いいわ。お金は取らない。その代わりに話して。","ENG":"All right. I won't take your money then. But tell me a story instead.","TWN":"好吧，我不收錢。你陪我聊聊天就好。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어쩌다 그렇게 다쳐서 여기까지 오게 된 건지.","JPN":"どうしてそんな怪我をして、ここまで来たのか。","ENG":"How did you end up here with all those wounds?","TWN":"像是你怎麼會傷成這樣還跑來這裡。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…사람을 해쳤어. 그런 얘기를 가십거리로 쓰고 싶진 않아.","JPN":"……人を害した。そんな話をゴシップにしたくはない。","ENG":"...I hurt a person. But I don't want to gossip about something like that.","TWN":"……我傷害了一個人。我不想把那種事當成八卦話題。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"처음이구나? 사람을 해쳐본 건.","JPN":"初めてなんだ？　人を傷つけたの。","ENG":"Is it your first time? Hurting another person?","TWN":"這是第一次吧？傷害人的事。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"하지만, 아직 그걸 즐기는 성격은 못되는 모양이네?","JPN":"でも、まだそれを楽しめる性格じゃないんだね。","ENG":"But it seems like you didn't really enjoy it.","TWN":"但你看起來還不會享受那種感覺？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};